import { useEffect, useState } from 'react'
import { useNavigate } from 'react-router-dom'
import { motion } from 'framer-motion'
import { supabase } from '@/lib/supabase'
import { awardXp } from '@/lib/xp'
import { fireFlowerConfetti } from '@/lib/confetti'
import { Header } from '@/components/Header'
import { XPToast, type XpToastData } from '@/components/XPToast'
import { ScoreScreen } from '@/components/ScoreScreen'

// Modus 8 — Synonym-Match laut CLAUDE.md §6.8.
//   Quelle: synonym_pairs_medical (13 Paare)
//   Variante 1 (hier umgesetzt): HU↔HU-Matching wie Modus 2
//   XP: 10 pro Match
//
// Im Gegensatz zu Wörterpaare (DE/HU) sind hier beide Spalten ungarisch —
// die Lernende muss erkennen welche zwei HU-Begriffe dasselbe bedeuten.

const ROUND_SIZE = 6  // 6 Paare pro Runde, sind nur 13 verfügbar

type Pair = { id: number; term_a: string; term_b: string; german: string | null }

type Side = 'a' | 'b'
type SelKey = `${Side}:${number}`

function shuffle<T>(a: T[]): T[] { const c = [...a]; for (let i = c.length - 1; i > 0; i--) { const j = Math.floor(Math.random() * (i + 1)); [c[i], c[j]] = [c[j], c[i]] } return c }

export default function SynonymMatch() {
  const navigate = useNavigate()
  const [pool, setPool] = useState<Pair[] | null>(null)
  const [round, setRound] = useState<Pair[]>([])
  const [aOrder, setAOrder] = useState<number[]>([])
  const [bOrder, setBOrder] = useState<number[]>([])
  const [matched, setMatched] = useState<Set<number>>(new Set())
  const [selected, setSelected] = useState<SelKey | null>(null)
  const [wrong, setWrong] = useState<SelKey | null>(null)
  const [matches, setMatches] = useState(0)
  const [misses, setMisses] = useState(0)
  const [done, setDone] = useState(false)
  const [toast, setToast] = useState<XpToastData | null>(null)
  const [error, setError] = useState<string | null>(null)

  useEffect(() => {
    let cancelled = false
    async function load() {
      const { data, error } = await supabase
        .from('synonym_pairs_medical')
        .select('id, term_a, term_b, german')
      if (cancelled) return
      if (error) { setError(error.message); return }
      const all = (data ?? []) as Pair[]
      if (all.length < ROUND_SIZE) { setError(`Nur ${all.length} Synonympaare in der DB.`); return }
      setPool(all)
    }
    void load()
    return () => { cancelled = true }
  }, [])

  useEffect(() => { if (pool && pool.length > 0) startRound() /* eslint-disable-next-line */ }, [pool])

  function startRound() {
    if (!pool) return
    const r = shuffle(pool).slice(0, ROUND_SIZE)
    setRound(r)
    setAOrder(shuffle(r.map((_, i) => i)))
    setBOrder(shuffle(r.map((_, i) => i)))
    setMatched(new Set())
    setSelected(null); setWrong(null)
    setMatches(0); setMisses(0); setDone(false)
  }

  function handleClick(side: Side, idx: number) {
    if (matched.has(idx) || wrong || done) return
    const key: SelKey = `${side}:${idx}`
    if (!selected) { setSelected(key); return }
    if (selected === key) { setSelected(null); return }

    const [selSide, selIdxStr] = selected.split(':') as [Side, string]
    const selIdx = parseInt(selIdxStr, 10)
    if (selSide === side) { setSelected(key); return }

    if (selIdx === idx) {
      const next = new Set(matched); next.add(idx); setMatched(next); setSelected(null); setMatches((m) => m + 1)
      fireFlowerConfetti()
      if (next.size === round.length) {
        const xp = next.size * 10
        void awardXp({ baseAmount: xp, source: 'synonym_round_complete', mode: 'medical' })
          .then((r) => r && setToast({ id: Date.now(), ...r }))
        setDone(true)
      }
    } else {
      setWrong(key); setMisses((m) => m + 1)
      setTimeout(() => { setWrong(null); setSelected(null) }, 450)
    }
  }

  useEffect(() => { if (toast) { const t = setTimeout(() => setToast(null), 1200); return () => clearTimeout(t) } }, [toast])

  if (error) return <Wrap><Status>⚠ {error}</Status><Back nav={navigate} /></Wrap>
  if (!pool) return <Wrap><Status>Wird geladen…</Status></Wrap>
  if (done) {
    return (
      <ScoreScreen
        emoji="🔁"
        title="Runde geschafft!"
        subtitle={misses === 0 ? 'Perfekt — kein Fehlversuch' : `${misses} Fehlversuche`}
        stats={[
          { label: 'Synonyme', value: matches, highlight: true },
          { label: 'Fehlversuche', value: misses },
          { label: 'Gemeinsame DE-Bedeutung', value: round[0]?.german ? 'siehe Paare' : '—' }
        ]}
        totalXp={matches * 10}
        primaryAction={{ label: 'Nochmal', onClick: startRound }}
        secondaryAction={{ label: 'Zurück zu Home', onClick: () => navigate('/home') }}
      />
    )
  }

  return (
    <Wrap>
      <div style={{ width: '100%', maxWidth: 480, display: 'flex', justifyContent: 'space-between', fontSize: '0.85rem', opacity: 0.7, marginBottom: '0.4rem' }}>
        <span>Synonyme: {matches} / {round.length}</span>
        <span>Fehler: {misses}</span>
      </div>
      <div style={{ width: '100%', maxWidth: 480, display: 'grid', gridTemplateColumns: '1fr 1fr', gap: 10 }}>
        <Col>
          {aOrder.map((i) => {
            const key: SelKey = `a:${i}`
            return <Tile key={key} text={round[i].term_a} state={tileState(key, selected, wrong, matched.has(i))} onClick={() => handleClick('a', i)} />
          })}
        </Col>
        <Col>
          {bOrder.map((i) => {
            const key: SelKey = `b:${i}`
            return <Tile key={key} text={round[i].term_b} state={tileState(key, selected, wrong, matched.has(i))} onClick={() => handleClick('b', i)} />
          })}
        </Col>
      </div>
      <Back nav={navigate} />
      <XPToast toast={toast} />
    </Wrap>
  )
}

type TileState = 'idle' | 'selected' | 'wrong' | 'matched'
function tileState(k: SelKey, sel: SelKey | null, wr: SelKey | null, m: boolean): TileState {
  if (m) return 'matched'; if (wr === k) return 'wrong'; if (sel === k) return 'selected'; return 'idle'
}

function Tile({ text, state, onClick }: { text: string; state: TileState; onClick: () => void }) {
  const c = {
    idle:     { bg: 'var(--white)', border: 'rgba(0,0,0,0.15)', color: 'inherit' },
    selected: { bg: 'var(--white)', border: 'var(--orange)',    color: 'var(--orange)' },
    wrong:    { bg: 'rgba(200,21,10,0.12)', border: 'var(--red)',    color: 'var(--red)' },
    matched:  { bg: 'rgba(62,90,10,0.12)',  border: 'var(--green)',  color: 'var(--green)' }
  }[state]
  return (
    <motion.button onClick={onClick} disabled={state === 'matched'} animate={state === 'wrong' ? { x: [0, -4, 4, -4, 4, 0] } : {}} transition={{ duration: 0.4 }} style={{ background: c.bg, border: `2px solid ${c.border}`, color: c.color, padding: '0.85rem 0.6rem', borderRadius: 12, fontFamily: 'Georgia, serif', fontWeight: 700, fontSize: '0.95rem', cursor: state === 'matched' ? 'default' : 'pointer', minHeight: 56, opacity: state === 'matched' ? 0.55 : 1, textAlign: 'center' }}>
      {text}
    </motion.button>
  )
}

function Col({ children }: { children: React.ReactNode }) { return <div style={{ display: 'flex', flexDirection: 'column', gap: 8 }}>{children}</div> }
function Wrap({ children }: { children: React.ReactNode }) { return (<div style={{ minHeight: '100vh', display: 'flex', flexDirection: 'column', background: 'var(--cream)' }}><Header /><main style={{ flex: 1, display: 'flex', flexDirection: 'column', alignItems: 'center', padding: '1.5rem 1rem 3rem' }}>{children}</main></div>) }
function Status({ children }: { children: React.ReactNode }) { return <div style={{ opacity: 0.55, marginTop: '20vh' }}>{children}</div> }
function Back({ nav }: { nav: ReturnType<typeof useNavigate> }) { return <button onClick={() => nav('/home')} style={{ marginTop: '1.5rem', background: 'none', border: '1.5px solid rgba(0,0,0,0.15)', padding: '0.45rem 0.9rem', borderRadius: 8, fontFamily: 'inherit', fontSize: '0.8rem', cursor: 'pointer', opacity: 0.65 }}>Sitzung abbrechen</button> }
